const AIRLINE_PALETTE = ["#1E2761", "#0D9488", "#B45309", "#6D5BA8", "#0E7490", "#9D174D", "#3F6212"];
function airlineColor(name) {
  let hash = 0;
  for (let i = 0; i < name.length; i++) hash = (hash * 31 + name.charCodeAt(i)) % AIRLINE_PALETTE.length;
  return AIRLINE_PALETTE[Math.abs(hash) % AIRLINE_PALETTE.length];
}
function AirlineLogo({ name, size = "md" }) {
  const code = AIRLINE_CODES[name] || name.slice(0, 2).toUpperCase();
  const color = airlineColor(name);
  const box = size === "sm" ? "w-8 h-8 rounded-lg" : "w-10 h-10 rounded-xl";
  return (
    <div
      className={`${box} flex items-center justify-center text-white font-semibold text-xs shrink-0`}
      style={{ backgroundColor: color }}
      title={name}
      aria-label={name}
    >
      {code}
    </div>
  );
}

