const LOGO_PNG_BASE64 = "";
const SEAL_OURO_BASE64 = "";
const SEAL_DIAMANTE_BASE64 = "";

function Logo({ compact = false, dark = false }) {
  const img = (
    <img
      src={`data:image/png;base64,${LOGO_PNG_BASE64}`}
      alt="TPAir Bússola"
      style={compact ? { height: 36, width: "auto" } : { height: 40, width: "auto" }}
    />
  );
  if (!dark) return img;
  // A arte original usa tons escuros (navy/teal) e perde contraste em fundo escuro;
  // aqui adicionamos um fundo branco atrás dela (sem alterar a imagem) só no tema escuro.
  return (
    <div className="inline-block bg-white rounded-lg px-2 py-1.5">
      {img}
    </div>
  );
}

