// Deriva abertura/máxima/mínima/fechamento por mês a partir do volume de vendas, para o gráfico de velas
// (abertura = fechamento do mês anterior; máxima/mínima simulam a melhor e a pior semana dentro do mês).
const MONTHLY_CANDLES = MONTHLY.map((m, i) => {
  const open = i === 0 ? Math.round(m.vendas * 0.74) : MONTHLY[i - 1].vendas;
  const close = m.vendas;
  const high = Math.round(Math.max(open, close) * 1.09);
  const low = Math.round(Math.min(open, close) * 0.88);
  return { mes: m.mes, open, close, high, low };
});

