function getTierInfo(volume) {
  let current = TIERS[0];
  for (const t of TIERS) if (volume >= t.min) current = t;
  const idx = TIERS.findIndex(t => t.id === current.id);
  const next = TIERS[idx + 1] || null;
  const pct = next ? Math.round(((volume - current.min) / (next.min - current.min)) * 100) : 100;
  return { current, next, pct, falta: next ? next.min - volume : 0 };
}

