// ---------- integração com o Backoffice TPAir (sistema separado, da consolidadora) ----------
// O Backoffice grava neste mesmo localStorage do navegador (quando aberto no mesmo
// navegador/computador). Ao carregar, o Bússola procura por dados cadastrados para
// esta agência e, se existirem, substituem os dados de exemplo abaixo.
const SHARED_DATA_KEY = "tpair_bussola_shared_data_v1";
const CURRENT_AGENCY_ID = "flytop-viagens";
let USING_BACKOFFICE_DATA = false;

function applyBackofficeOverrides() {
  try {
    if (typeof window === "undefined" || !window.localStorage) return;
    const raw = window.localStorage.getItem(SHARED_DATA_KEY);
    if (!raw) return;
    const data = JSON.parse(raw);

    const agency = data.agencies && data.agencies[CURRENT_AGENCY_ID];
    if (agency) {
      if (typeof agency.annualVolume === "number") {
        AGENCY_ANNUAL_VOLUME = agency.annualVolume;
      }
      if (agency.tierThresholds) {
        TIERS.forEach(t => {
          if (typeof agency.tierThresholds[t.id] === "number") t.min = agency.tierThresholds[t.id];
        });
        USING_BACKOFFICE_DATA = true;
      }
      if (Array.isArray(agency.goals) && agency.goals.length) {
        GOALS.length = 0;
        agency.goals.forEach(g => GOALS.push(g));
        USING_BACKOFFICE_DATA = true;
      }
      if (Array.isArray(agency.challenges) && agency.challenges.length) {
        CHALLENGES.length = 0;
        agency.challenges.forEach(c => CHALLENGES.push(c));
        USING_BACKOFFICE_DATA = true;
      }
    }

    if (Array.isArray(data.campaigns) && data.campaigns.length) {
      const eligible = data.campaigns.filter(c =>
        c.agenciasElegiveis === "todas" ||
        (Array.isArray(c.agenciasElegiveis) && c.agenciasElegiveis.includes(CURRENT_AGENCY_ID))
      );
      if (eligible.length) {
        INITIAL_CAMPAIGNS.length = 0;
        eligible.forEach(c => INITIAL_CAMPAIGNS.push({ ...c, tickets: c.tickets || [] }));
        USING_BACKOFFICE_DATA = true;
      }
    }
  } catch (e) {
    console.warn("Bússola: não foi possível carregar dados do Backoffice.", e);
  }
}
applyBackofficeOverrides();

function formatBRL(n) {
  return "R$ " + Number(n || 0).toLocaleString("pt-BR", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

// converte "8.420,00" (formato BR) em número
function parseValorBR(str) {
  return parseFloat(String(str).replace(/\./g, "").replace(",", ".")) || 0;
}

// quanto a agência já garantiu de bônus/incentivo com os bilhetes cadastrados nessa campanha
function valorAlcancado(campaign) {
  if (campaign.tipo === "incentivo") {
    return campaign.tickets.reduce((sum, t) => sum + parseValorBR(t.valor) * (campaign.percentualIncentivo / 100), 0);
  }
  return campaign.tickets.length * (campaign.valorPorBilhete || 0);
}

// extrai o(s) percentual(is) de um campo "repasse" (ex.: "2%+5%" -> 7); "FEE" -> null (sem incentivo público)
function parseRepasseValue(str) {
  if (!str || /fee/i.test(str)) return null;
  const matches = str.match(/[\d.,]+(?=%)/g);
  if (!matches) return null;
  return matches.reduce((sum, m) => sum + parseFloat(m.replace(",", ".")), 0);
}

// melhor repasse público de uma companhia, para exibir no "tijolinho"
function melhorRepasse(linhas) {
  const valores = linhas.map(l => parseRepasseValue(l.repasse)).filter(v => v !== null);
  if (valores.length === 0) return null;
  return Math.max(...valores);
}

// conta o tempo restante de um desafio-relâmpago, atualizando a cada 30s
function useCountdown(hoursFromNow) {
  const [deadline] = useState(() => Date.now() + hoursFromNow * 3600 * 1000);
  const [now, setNow] = useState(() => Date.now());
  useEffect(() => {
    const id = setInterval(() => setNow(Date.now()), 30000);
    return () => clearInterval(id);
  }, []);
  const remainingMs = Math.max(0, deadline - now);
  const totalMin = Math.floor(remainingMs / 60000);
  const days = Math.floor(totalMin / (60 * 24));
  const hours = Math.floor((totalMin % (60 * 24)) / 60);
  const minutes = totalMin % 60;
  const label = days > 0 ? `${days}d ${hours}h restantes` : hours > 0 ? `${hours}h restantes` : `${minutes}min restantes`;
  return { label, expired: remainingMs <= 0 };
}

