// botão de copiar (ex.: localizador) para colar em outro sistema, com confirmação visual
function CopyButton({ text, label = "Copiar localizador" }) {
  const [copied, setCopied] = useState(false);

  function handleCopy(e) {
    e.stopPropagation();
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(text).catch(() => {});
    }
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  }

  return (
    <button
      onClick={handleCopy}
      title={copied ? "Copiado!" : label}
      aria-label={label}
      className="inline-flex items-center justify-center w-6 h-6 rounded-md border border-slate-200 text-slate-400 hover:text-slate-700 hover:border-slate-300 dark:border-slate-700 dark:text-slate-500 dark:hover:text-slate-200 dark:hover:border-slate-600 shrink-0 transition-colors"
    >
      {copied ? <Check className="w-3.5 h-3.5" style={{ color: BRAND.tealDark }} /> : <Copy className="w-3.5 h-3.5" />}
    </button>
  );
}

