function CandlestickChart({ data }) {
  const allValues = data.flatMap(d => [d.open, d.close, d.high, d.low]);
  const maxV = Math.max(...allValues);
  const minV = Math.min(...allValues) * 0.95;
  const range = maxV - minV || 1;
  const H = 170;
  const stepW = 100 / data.length;
  const toY = v => H - ((v - minV) / range) * H;

  return (
    <div className="mt-6 pt-5 border-t border-slate-100 dark:border-slate-800">
      <div className="flex items-center justify-between mb-1">
        <p className="font-semibold text-slate-900 dark:text-slate-50">Variação mensal (gráfico de velas)</p>
        <div className="flex items-center gap-3 text-xs text-slate-400 dark:text-slate-500">
          <span className="inline-flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm" style={{ backgroundColor: BRAND.teal }} /> Em alta</span>
          <span className="inline-flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-rose-500" /> Em queda</span>
        </div>
      </div>
      <p className="text-xs text-slate-400 dark:text-slate-500 mb-3">Cada vela mostra a faixa de vendas do mês: corpo entre a abertura e o fechamento, linha até a melhor e a pior semana.</p>
      <svg viewBox={`0 0 100 ${H + 14}`} preserveAspectRatio="none" className="w-full" style={{ height: H + 30 }}>
        {data.map((d, i) => {
          const cx = stepW * i + stepW / 2;
          const isUp = d.close >= d.open;
          const color = isUp ? BRAND.teal : "#E11D48";
          const bodyTop = toY(Math.max(d.open, d.close));
          const bodyBottom = toY(Math.min(d.open, d.close));
          const bodyW = stepW * 0.38;
          return (
            <g key={i}>
              <line x1={cx} x2={cx} y1={toY(d.high)} y2={toY(d.low)} stroke={color} strokeWidth="0.6" />
              <rect
                x={cx - bodyW / 2}
                y={bodyTop}
                width={bodyW}
                height={Math.max(1.5, bodyBottom - bodyTop)}
                fill={color}
                rx="0.6"
              />
            </g>
          );
        })}
      </svg>
      <div className="flex mt-1">
        {data.map((d, i) => (
          <span key={i} className="text-xs text-slate-400 dark:text-slate-500 text-center" style={{ width: `${stepW}%` }}>{d.mes}</span>
        ))}
      </div>
    </div>
  );
}

