function CampaignsModule() {
  const [campaigns, setCampaigns] = useState(INITIAL_CAMPAIGNS);
  const [modalFor, setModalFor] = useState(null);
  const [rulesFor, setRulesFor] = useState(null);
  const [toast, setToast] = useState(null);
  const [expanded, setExpanded] = useState({});

  function addTicket(campaignId, ticket) {
    setCampaigns(cs => cs.map(c => c.id === campaignId ? { ...c, tickets: [...c.tickets, ticket] } : c));
    setModalFor(null);
    setToast("Bilhete cadastrado na campanha.");
    setTimeout(() => setToast(null), 2500);
  }

  function downloadTickets(c) {
    const header = "Localizador,Rota,Classe,Valor,Data de emissão";
    const rows = c.tickets.map(t => [t.localizador, t.rota, t.classe, t.valor, t.data].join(","));
    const csv = [header, ...rows].join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `bilhetes_${c.companhia.replace(/\s+/g, "_")}_${c.id}.csv`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
  }

  return (
    <div>
      <SectionTitle eyebrow="Campanhas ativas" title="Bônus e incentivos vigentes com companhias aéreas" />
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {campaigns.map(c => {
          const hasMeta = c.meta != null;
          const pct = hasMeta ? Math.round((c.tickets.length / c.meta) * 100) : 0;
          const ganho = valorAlcancado(c);
          return (
            <div key={c.id} className="rounded-2xl border border-slate-200 bg-white p-6 flex flex-col dark:border-slate-700 dark:bg-slate-800">
              <div className="flex items-start justify-between mb-3">
                <div className="flex items-center gap-3">
                  <AirlineLogo name={c.companhia} />
                  <div>
                    <p className="font-semibold text-slate-900 dark:text-slate-50">{c.companhia}</p>
                    <p className="text-xs text-slate-400 dark:text-slate-500">{c.inicio} – {c.fim}</p>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <span
                    className="text-xs font-medium px-2.5 py-1 rounded-full"
                    style={c.status === "Ativa" ? { backgroundColor: "#EAF6F4", color: BRAND.tealDark } : { backgroundColor: "#FFF1E0", color: "#B45309" }}
                  >
                    {c.status}
                  </span>
                  <button
                    onClick={() => setRulesFor(c.id)}
                    title="Ver regras completas da campanha"
                    aria-label="Ver regras completas da campanha"
                    className="w-6 h-6 rounded-full border border-slate-300 text-slate-500 flex items-center justify-center text-sm font-semibold hover:border-slate-400 hover:text-slate-700 dark:border-slate-600 dark:text-slate-400 dark:hover:border-slate-500 dark:hover:text-slate-200"
                  >
                    +
                  </button>
                </div>
              </div>

              <span
                className="text-xs font-medium px-2 py-0.5 rounded-full inline-flex items-center gap-1 w-fit mb-2"
                style={c.tipo === "incentivo" ? { backgroundColor: "#EFEBFB", color: "#6D5BA8" } : { backgroundColor: "#FFF4DF", color: "#B45309" }}
              >
                {c.tipo === "incentivo" ? <Percent className="w-3 h-3" /> : <Gift className="w-3 h-3" />}
                {c.tipo === "incentivo" ? "Incentivo de comissão" : "Bônus por emissão"}
              </span>

              <p className="text-sm text-slate-700 dark:text-slate-300">{c.regra}</p>
              <p className="text-sm text-slate-500 mt-1 dark:text-slate-400">Recompensa: {c.recompensa}</p>

              <div className="mt-4">
                {hasMeta ? (
                  <>
                    <div className="flex justify-between text-xs text-slate-500 mb-1 dark:text-slate-400">
                      <span>{c.tickets.length} de {c.meta} bilhetes cadastrados</span>
                      <span>{pct}%</span>
                    </div>
                    <ProgressBar pct={pct} height={8} />
                  </>
                ) : (
                  <p className="text-xs text-slate-500 dark:text-slate-400">{c.tickets.length} bilhete{c.tickets.length === 1 ? "" : "s"} cadastrado{c.tickets.length === 1 ? "" : "s"} · sem meta mínima, vale para cada emissão</p>
                )}
              </div>

              <div
                className="mt-3 rounded-xl p-3 flex items-center gap-2.5"
                style={{ backgroundColor: c.tickets.length > 0 ? "#EAF6F4" : "#F8FAFC" }}
              >
                <Wallet className="w-4 h-4 shrink-0" style={{ color: c.tickets.length > 0 ? BRAND.tealDark : "#94A3B8" }} />
                {c.tickets.length > 0 ? (
                  <p className="text-sm font-medium" style={{ color: BRAND.tealDark }}>
                    Você cadastrou {c.tickets.length} bilhete{c.tickets.length === 1 ? "" : "s"} e tem {formatBRL(ganho)} para receber!
                  </p>
                ) : (
                  <p className="text-sm text-slate-500 dark:text-slate-400">Cadastre seu primeiro bilhete para começar a acumular valor nesta campanha.</p>
                )}
              </div>

              {c.tickets.length > 0 && (
                <div className="mt-2">
                  <button
                    onClick={() => setExpanded(ex => ({ ...ex, [c.id]: !ex[c.id] }))}
                    className="text-xs font-medium inline-flex items-center gap-1 text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200"
                  >
                    <ChevronDown className={`w-3.5 h-3.5 transition-transform ${expanded[c.id] ? "rotate-180" : ""}`} />
                    {expanded[c.id] ? "Ocultar bilhetes cadastrados" : "Ver bilhetes cadastrados"}
                  </button>
                  {expanded[c.id] && (
                    <div className="mt-2 space-y-1.5">
                      {c.tickets.map((t, i) => (
                        <div key={i} className="flex items-center justify-between gap-2 rounded-lg border border-slate-100 px-3 py-2 text-xs dark:border-slate-700">
                          <span className="flex items-center gap-1.5">
                            <span className="font-mono text-slate-700 dark:text-slate-300">{t.localizador}</span>
                            <CopyButton text={t.localizador} label="Copiar localizador" />
                          </span>
                          <span className="text-slate-400 dark:text-slate-500 truncate">{t.rota} · {t.classe}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              <div className="mt-5 flex gap-2 pt-4 border-t border-slate-100 dark:border-slate-800">
                <button
                  onClick={() => setModalFor(c.id)}
                  className="flex-1 inline-flex items-center justify-center gap-1.5 rounded-lg py-2 text-sm font-medium text-white"
                  style={{ backgroundColor: BRAND.teal }}
                >
                  <Plus className="w-4 h-4" /> Cadastrar bilhete emitido
                </button>
                <button
                  onClick={() => downloadTickets(c)}
                  disabled={c.tickets.length === 0}
                  className="flex-1 inline-flex items-center justify-center gap-1.5 rounded-lg py-2 text-sm font-medium border border-slate-200 text-slate-700 disabled:opacity-40 hover:bg-slate-50 dark:border-slate-700 dark:text-slate-300 dark:hover:bg-slate-700"
                >
                  <Download className="w-4 h-4" /> Baixar bilhetes cadastrados
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {modalFor && (
        <TicketModal
          campaign={campaigns.find(c => c.id === modalFor)}
          onClose={() => setModalFor(null)}
          onSave={(ticket) => addTicket(modalFor, ticket)}
        />
      )}
      {rulesFor && (
        <RulesModal
          campaign={campaigns.find(c => c.id === rulesFor)}
          onClose={() => setRulesFor(null)}
        />
      )}
      {toast && (
        <div className="fixed bottom-6 right-6 bg-slate-900 text-white text-sm px-4 py-3 rounded-xl flex items-center gap-2 shadow-lg z-50">
          <CheckCircle2 className="w-4 h-4" style={{ color: BRAND.amber }} /> {toast}
        </div>
      )}
    </div>
  );
}

